import{_ as t,c as a,a1 as r,o}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Information Gathering using theHarvester","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/6-theHarvester.md","filePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/6-theHarvester.md"}'),i={name:"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/6-theHarvester.md"};function n(s,e,h,l,c,d){return o(),a("div",null,e[0]||(e[0]=[r('<h1 id="information-gathering-using-theharvester" tabindex="-1">Information Gathering using theHarvester <a class="header-anchor" href="#information-gathering-using-theharvester" aria-label="Permalink to &quot;Information Gathering using theHarvester&quot;">​</a></h1><p>theHarvester is used to gather open source intelligence (OSINT) on a company or domain. theHarvester gathers emails, subdomains, hosts, employee names, open ports and banners from different public sources like search engines, PGP key servers and SHODAN computer database.</p><p><em>Official repository:</em> <a href="https://github.com/laramies/theHarvester" target="_blank" rel="noreferrer">https://github.com/laramies/theHarvester</a></p><h2 id="overview-of-theharvester" tabindex="-1">Overview of theHarvester <a class="header-anchor" href="#overview-of-theharvester" aria-label="Permalink to &quot;Overview of theHarvester&quot;">​</a></h2><p>Has been developed in Python by Christian Martorella. It&#39;s a very helpful tool in the early stages of penetration test. Help to undestand the customer footprint on the internet. Some professionals also use theHarvester to review the information available to an attacker through the internet.</p><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li>Kali Linux virtual machine.</li></ul><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><ul><li>Demonstrate how to identify vulnerabilities and information disclosures in search engines using theHarvester.</li><li>Extract email, subdomain names, virtual hosts(...) from the web sites.</li></ul><hr><h2 id="run-theharvester-against-a-target" tabindex="-1">Run theHarvester against a target <a class="header-anchor" href="#run-theharvester-against-a-target" aria-label="Permalink to &quot;Run theHarvester against a target&quot;">​</a></h2><p>To view all the commands option, type:</p><p><code>theHarvester -h</code></p><p>Let&#39;s perform a full harvest on this target:</p><p><code>theHarvester -d certifiedhacker.com -l 300 -b all</code></p><p>On the <code>help</code> command you can see the meaning of these options, like <code>-d</code> stands for domain, and <code>-l</code> for limit the number of search results, and <code>-b</code> is the search engine/source.</p><p>theHarvester may return too much information to go through, for better readability, you can write the output to an HTML file:</p><p><code>theHarvester -d certifiedhacker.com -l 300 -b all -f report</code></p><p>The file will be exported in your home folder in Kali Machine.</p><p>Note: If you having trouble to export the HTML file, keep in mind it&#39;s a huge amount of information being collected, you can reduce the search engines/sources, instead to use them all at once.</p>',20)]))}const p=t(i,[["render",n]]);export{m as __pageData,p as default};
